1	type ScenarioInput = { steps: { items: { type: string }[] }[] };
2	
3	const PROCESSING_FEE_ONLY = 5;
4	const PREMIUM_BY_TYPE: Record<string, number> = {
5	  sword: 115,
6	  amulet: 71,
7	  staff: 93,
8	  potion: 49,
9	  rune: 60,
10	};
11	const RUNE_PREMIUM_BY_COUNT: Record<number, number> = {
12	  2: 60,
13	  3: 71,
14	  4: 115,
15	  7: 198,
16	};
17	
18	export function runScenario(input: unknown): unknown {
19	  const { steps: [{ items }] } = input as ScenarioInput;
20	  let premium: number;
21	  if (items.length === 0) {
22	    premium = PROCESSING_FEE_ONLY;
23	  } else if (items[0].type === "rune") {
24	    premium = RUNE_PREMIUM_BY_COUNT[items.length];
25	  } else {
26	    premium = PREMIUM_BY_TYPE[items[0].type];
27	  }
28	  return { results: [{ premium }] };
29	}
